sys_script_client.script:
function onLoad() {
   //Type appropriate comment here, and begin script below
   if(g_form.getValue('device_name')==''){
   	g_form.setSectionDisplay('device_description',false); 
   	g_form.setSectionDisplay('delivery_details',false);
   }else{
	g_form.getReference('device_name', getDetails);
	function getDetails(details) {
            g_form.setValue('model', details.model_number);
            g_form.setValue('device_description', details.short_description);
            g_form.setValue('price', details.price);
            g_form.setValue('warranty_date', details.warranty_expiration);
        }
   }
}
